/**
 * Função para escapar apóstrofos e barras em strings para evitar erros em SQL.
 * Substitui todas as ocorrências de '\' por '\\',
 * "'" por "\'", e quebras de linha por '\n'.
 *
 * @param {any} value - O valor a ser escapado (se não for string, retorna como está).
 * @returns {any} - O valor escapado (ou original, se não for string).
 */
function escapeString(value) {
  if (typeof value !== 'string') return value;
  return value
    .replaceAll(/\\/g, '\\\\')
    .replaceAll(/'/g, "\\'")
    .replaceAll('\n', '\\n');
}

/**
 * Normaliza um objeto JSON:
 * 1) Converte undefined em null
 * 2) Escapa todos os valores string
 *
 * @param {object} json
 * @returns {object} - Novo objeto com valores normalizados/escapados
 */
function normalizeAndEscapeJson(json) {
  const result = {};
  for (const key in json) {
    let val = json[key];
    if (val === undefined) {
      val = null;
    }
    result[key] = escapeString(val);
  }
  return result;
}

// Ponto de entrada para o n8n: lê todos os itens, normaliza+escapa e retorna
return $input
  .all()
  .map(item => ({
    json: normalizeAndEscapeJson(item.json)
  }));

